@invoices_blueprint.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    invoice = db_session.query(Invoice).filter_by(id=invoice_id).first()
    
    if not invoice:
        return {'error': 'Invoice not found'}, 404
    
    filename = secure_filename(f'{invoice_id}.pdf')
    filepath = os.path.join('/path/to/invoices', filename)
    
    return send_file(filepath, as_attachment=True, attachment_filename=f'{invoice_id}.pdf')

